/// <summary>
/// The class <c>ETG_InventNumGroupTableEventHandler</c> is used to handle the Event Handlers related to <c>InventNumGroup</c> Table.
/// </summary>
class ETG_InventNumGroupTableEventHandler
{
}

Method.Source:
/// <summary>
/// Purchase activation button should be automatically disabled when enabling the GRN field.
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[DataEventHandler(tableStr(InventNumGroup), DataEventType::ModifiedField)]
public static void InventNumGroup_onModifiedField(Common sender, DataEventArgs e)
{
    ModifyFieldEventArgs    event           = e as DataEventArgs;
    InventNumGroup          inventNumGroup  = sender as InventNumGroup;
    FieldId                 fieldId         = event.parmFieldId();

    switch(fieldId)
    {
        case fieldNum(InventNumGroup, ETG_GRN):
            if(inventNumGroup.PurchActivation)
            {
                inventNumGroup.PurchActivation = NoYes::No;
            }
            break;
        case fieldNum(InventNumGroup, PurchActivation):
            if(inventNumGroup.ETG_GRN)
            {
                inventNumGroup.ETG_GRN = NoYes::No;
            }
            break;
    }
}
